		$display("Mismatches: %1d in %1d samples", stats1.errors, stats1.clocks);

		if(stats1.errors==0)$display("SIMULATION PASSED");
		else $display("SIMULATION FAILED - %d MISMATCHES DETECTED, FIRST AT TIME %d",stats1.errors,stats1.errortime_anyedge);
	end

