			stats1.errors++;
		end
		if (anyedge_ref [0] !== ( anyedge_ref [0] ^ anyedge_dut [0] ^ anyedge_ref [0]))
		begin if (stats1.errors_anyedge == 0) stats1.errortime_anyedge = $time;
			stats1.errors_anyedge = stats1.errors_anyedge+1'b1; end

		if(stats1.errors==0 && tb_match)$display("SIMULATION PASSED");
		else $display("SIMULATION FAILED - %d MISMATCHES DETECTED, FIRST AT TIME %d",stats1.errors,stats1.errortime_anyedge);

		if(tb_match)begin
			$display("Cycle %d, input %b, got output %b, exp output %b",
				stats1.clocks,
				in [0],
				anyedge_dut [0],
				anyedge_ref [0]
			);
		end

